import React, { useState } from 'react';
import { Button, Select, StatusBadge, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { hrService } from '../../../services/ns/hrService';
import type { PayslipDto } from '../../../services/ns/models';
import { formatVnd } from '../../../utils/format';
import styles from '../../../styles/erpPage.module.css';

const MONTH_OPTIONS = Array.from({ length: 12 }, (_, i) => ({ value: String(i + 1), label: `T${i + 1}` }));
const YEAR_OPTIONS = [2025, 2026, 2027].map(y => ({ value: String(y), label: String(y) }));

const BangLuongPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(now.getMonth() + 1);
  const [year, setYear] = useState(now.getFullYear());
  const [rows, setRows] = useState<PayslipDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [calcConfirm, setCalcConfirm] = useState(false);
  const [confirmPayroll, setConfirmPayroll] = useState(false);
  const [busy, setBusy] = useState(false);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      hrService.getPayslips({ month, year, pageSize: 500 })
        .then(res => { if (!cancelled) setRows(res.items); })
        .catch(err => {
          if (!cancelled)
            dispatch(addToast({ message: err?.message ?? 'Lỗi tải bảng lương', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [month, year, dispatch]);

  const totalNet = rows.reduce((s, r) => s + r.netSalary, 0);
  const totalGross = rows.reduce((s, r) => s + r.grossSalary, 0);

  const handleCalculate = async () => {
    setBusy(true);
    try {
      await hrService.calculatePayroll(month, year);
      dispatch(addToast({ message: 'Tính lương thành công', type: 'success' }));
      setCalcConfirm(false);
      const res = await hrService.getPayslips({ month, year, pageSize: 500 });
      setRows(res.items);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Tính lương thất bại', type: 'error' }));
    } finally {
      setBusy(false);
    }
  };

  const handleConfirm = async () => {
    setBusy(true);
    try {
      await hrService.confirmPayroll(month, year);
      dispatch(addToast({ message: 'Xác nhận bảng lương thành công', type: 'success' }));
      setConfirmPayroll(false);
      const res = await hrService.getPayslips({ month, year, pageSize: 500 });
      setRows(res.items);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Xác nhận thất bại', type: 'error' }));
    } finally {
      setBusy(false);
    }
  };

  const handleExport = () => {
    const qs = new URLSearchParams({ month: String(month), year: String(year) });
    const a = document.createElement('a');
    a.href = `${import.meta.env.VITE_API_URL}/hr/payslips/export-excel?${qs}`;
    a.download = `Bang-luong-T${month}-${year}.xlsx`;
    a.click();
  };

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-money-check-alt" /> Bảng lương tháng {month}/{year}</h1>
        </div>
        <div className={styles.headerActions}>
          <Select value={String(month)} onChange={e => setMonth(Number(e.target.value))} options={MONTH_OPTIONS} size="small" />
          <Select value={String(year)} onChange={e => setYear(Number(e.target.value))} options={YEAR_OPTIONS} size="small" />
          <Button variant="secondary" onClick={handleExport}><i className="fas fa-file-excel" /> Xuất Excel</Button>
          {calcConfirm ? (
            <>
              <Button variant="primary" onClick={handleCalculate} disabled={busy}>Xác nhận tính lương</Button>
              <Button variant="secondary" onClick={() => setCalcConfirm(false)}>Huỷ</Button>
            </>
          ) : (
            <Button variant="secondary" onClick={() => setCalcConfirm(true)} disabled={busy}>Tính lương</Button>
          )}
          {confirmPayroll ? (
            <>
              <Button variant="primary" onClick={handleConfirm} disabled={busy}>Xác nhận bảng lương</Button>
              <Button variant="secondary" onClick={() => setConfirmPayroll(false)}>Huỷ</Button>
            </>
          ) : (
            <Button variant="primary" onClick={() => setConfirmPayroll(true)} disabled={busy}>Xác nhận</Button>
          )}
        </div>
      </div>

      {rows.length > 0 && (
        <div className={styles.summaryBar}>
          <div className={styles.summaryItem}><label className={styles.label}>Số NV</label><strong>{rows.length}</strong></div>
          <div className={styles.summaryItem}><label className={styles.label}>Tổng thu nhập</label><strong>{formatVnd(totalGross)}</strong></div>
          <div className={styles.summaryItem}><label className={styles.label}>Tổng thực lĩnh</label><strong>{formatVnd(totalNet)}</strong></div>
        </div>
      )}

      <div className={styles.tableCard}>
        {loading ? (
          <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
        ) : rows.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Chưa có phiếu lương</p></div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Tên nhân viên</th>
                  <th className={styles.colRight}>Lương CB</th>
                  <th className={styles.colRight}>Lương khoán</th>
                  <th className={styles.colRight}>Tổng thu nhập</th>
                  <th className={styles.colRight}>Khấu trừ</th>
                  <th className={styles.colRight}>Thực lĩnh</th>
                  <th>TT</th>
                </tr>
              </thead>
              <tbody>
                {rows.map(r => (
                  <tr key={r.id}>
                    <td>{r.employeeName}</td>
                    <td className={styles.colRight}>{formatVnd(r.baseSalary)}</td>
                    <td className={styles.colRight}>{formatVnd(r.pieceRateAmount)}</td>
                    <td className={styles.colRight}>{formatVnd(r.grossSalary)}</td>
                    <td className={styles.colRight}>{formatVnd(r.deductions)}</td>
                    <td className={styles.colRight}><strong>{formatVnd(r.netSalary)}</strong></td>
                    <td><StatusBadge status={r.status} /></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default BangLuongPage;
